import React from 'react';
import { Layers } from 'lucide-react';

export default function ComparisonView() {
  return (
    <div className="min-h-[60vh] flex flex-col items-center justify-center text-center p-8 bg-white dark:bg-gray-800 rounded-3xl shadow-xl border border-dashed border-gray-300 dark:border-gray-700">
      <div className="p-4 bg-indigo-100 dark:bg-indigo-900/30 rounded-full text-indigo-600 mb-6">
        <Layers size={48} />
      </div>
      <h2 className="text-3xl font-black mb-4">Comparison View</h2>
      <p className="text-gray-500 dark:text-gray-400 max-w-md">
        We're building a tool to compare two handles head-to-head across all platforms. Stay tuned!
      </p>
    </div>
  );
}
